export const COLORS=[{name: 'Vàng',value: '#fff9c4',dark: '#fbc02d'},{name: 'Hồng',value: '#f8bbd9',dark: '#ec407a'},{name: 'Xanh dương',value: '#b3e5fc',dark: '#039be5'},{name: 'Xanh lá',value: '#c8e6c9',dark: '#43a047'},{name: 'Cam',value: '#ffe0b2',dark: '#fb8c00'},{name: 'Tím',value: '#e1bee7',dark: '#8e24aa'}];export const STORAGE_KEY='sadec-quick-notes';export const WIDGET_ID='quick-notes-widget';export const MODAL_ID='quick-note-edit-modal';export function getRandomColor(){return COLORS[Math.floor(Math.random()*COLORS.length)].value;}